  2	
  3	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  4	import DiskModal from '@kubevirt-utils/components/DiskModal/DiskModal';
  5	import { produceVMDisks } from '@kubevirt-utils/components/DiskModal/utils/helpers';
  6	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
  7	import KebabToggle from '@kubevirt-utils/components/toggles/KebabToggle';
  8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  9	import { getName } from '@kubevirt-utils/resources/shared';
 10	import { getDataVolumeTemplates, getDisks, getVolumes } from '@kubevirt-utils/resources/vm';
 11	import { DiskRowDataLayout } from '@kubevirt-utils/resources/vm/utils/disk/constants';
 12	import { getContentScrollableElement } from '@kubevirt-utils/utils/utils';
 13	import { ButtonVariant, Dropdown, DropdownItem, DropdownList } from '@patternfly/react-core';
 14	import { updateDisks } from '@virtualmachines/details/tabs/configuration/details/utils/utils';
 15	import { isRunning } from '@virtualmachines/utils';
 16	
 17	import CreateBootableVolumeModal from '../../modal/CreateBootableVolumeModal';
 18	import DeleteDiskModal from '../../modal/DeleteDiskModal';
 19	import DetachModal from '../../modal/DetachModal';
 20	import MakePersistentModal from '../../modal/MakePersistentModal';
 21	
 22	import { isHotplugVolume, isPVCSource } from './utils/helpers';
 23	
 24	type DiskRowActionsProps = {
 25	  customize?: boolean;
 26	  obj: DiskRowDataLayout;
 27	  onDiskUpdate?: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine>;
 28	  vm: V1VirtualMachine;
 29	  vmi?: V1VirtualMachineInstance;
 30	};
 31	
 32	const DiskRowActions: FC<DiskRowActionsProps> = ({
 33	  customize = false,
 34	  obj,
 35	  onDiskUpdate,
 36	  vm,
 37	  vmi,
 38	}) => {
 39	  const { t } = useKubevirtTranslation();
 40	  const { createModal } = useModal();
 41	
 42	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
 43	
 44	  const diskName = obj?.name;
 45	
 46	  const isVMRunning = isRunning(vm);
 47	  const isHotplug = isHotplugVolume(vm, diskName, vmi);
 48	
 49	  const volumes = isVMRunning ? vmi?.spec?.volumes : getVolumes(vm);
 50	  const volume = volumes?.find(({ name }) => name === diskName);
 51	
 52	  const editBtnText = t('Edit');
 53	  const deleteBtnText = t('Detach');
 54	  const removeHotplugBtnText = t('Make persistent');
 55	
 56	  const onCustomizeDeleteDisk = () => {
 57	    const newVM = produceVMDisks(vm, (draftVM) => {
 58	      const volumeToDelete = getVolumes(vm).find((v) => v.name === diskName);
 59	      draftVM.spec.template.spec.domain.devices.disks = getDisks(draftVM)?.filter(
 60	        (disk) => disk.name !== volumeToDelete.name,
 61	      );
 62	      draftVM.spec.template.spec.volumes = getVolumes(draftVM)?.filter(
 63	        (v) => v.name !== volumeToDelete.name,
 64	      );
 65	      draftVM.spec.dataVolumeTemplates = getDataVolumeTemplates(draftVM)?.filter(
 66	        (dataVolume) => getName(dataVolume) !== volumeToDelete?.dataVolume?.name,
 67	      );
 68	    });
 69	
 70	    return onDiskUpdate(newVM);
 71	  };
 72	
 73	  const createEditDiskModal = () =>
 74	    createModal(({ isOpen, onClose }) => (
 75	      <DiskModal
 76	        createdPVCName={isPVCSource(obj) ? obj?.source : null}
 77	        editDiskName={diskName}
 78	        isOpen={isOpen}
 79	        onClose={onClose}
 80	        onSubmit={onDiskUpdate || updateDisks}
 81	        vm={vm}
 82	      />
 83	    ));
 84	
 85	  const createDeleteDiskModal = () =>
 86	    createModal(({ isOpen, onClose }) =>
 87	      customize ? (
 88	        <DetachModal
 89	          diskName={diskName}
 90	          headerText={t('Detach disk?')}
 91	          isOpen={isOpen}
 92	          obj={vm}
 93	          onClose={onClose}
 94	          onSubmit={onCustomizeDeleteDisk}
 95	          submitBtnText={deleteBtnText}
 96	          submitBtnVariant={ButtonVariant.danger}
 97	        />
 98	      ) : (
 99	        <DeleteDiskModal
100	          isHotPluginVolume={isHotplug}
101	          isOpen={isOpen}
102	          onClose={onClose}
103	          vm={vm}
104	          volume={volume}
105	        />
106	      ),
107	    );
108	
109	  const createBootableVolume = () => {
110	    createModal(({ isOpen, onClose }) => (
111	      <CreateBootableVolumeModal diskObj={obj} isOpen={isOpen} onClose={onClose} vm={vm} />
112	    ));
113	  };
114	
115	  const makePersistent = () =>
116	    createModal(({ isOpen, onClose }) => (
117	      <MakePersistentModal isOpen={isOpen} onClose={onClose} vm={vm} vmi={vmi} volume={volume} />
118	    ));
119	
120	  const onModalOpen = (createModalCallback: () => void) => {
121	    createModalCallback();
122	    setIsDropdownOpen(false);
123	  };
124	
125	  const onToggle = () => setIsDropdownOpen((prevIsOpen) => !prevIsOpen);
126	
127	  return (
128	    <Dropdown
129	      isOpen={isDropdownOpen}
130	      onOpenChange={(open: boolean) => setIsDropdownOpen(open)}
131	      onSelect={() => setIsDropdownOpen(false)}
132	      popperProps={{ appendTo: getContentScrollableElement, position: 'right' }}
133	      toggle={KebabToggle({ id: 'toggle-id-6', isExpanded: isDropdownOpen, onClick: onToggle })}
134	    >
135	      <DropdownList>
136	        <DropdownItem
137	          isDisabled={!isPVCSource(obj)}
138	          key="disk-bootable-volume"
139	          onClick={() => createBootableVolume()}
140	        >
141	          {t('Save as bootable volume')}
142	        </DropdownItem>
143	        <DropdownItem key="disk-edit" onClick={() => onModalOpen(createEditDiskModal)}>
144	          {editBtnText}
145	        </DropdownItem>
146	        <DropdownItem key="disk-delete" onClick={() => onModalOpen(createDeleteDiskModal)}>
147	          {deleteBtnText}
148	        </DropdownItem>
149	        {isHotplug && (
150	          <DropdownItem
151	            description={t('Will make disk persistent on next reboot')}
152	            key="make-persistent"
153	            onClick={() => onModalOpen(makePersistent)}
154	          >
155	            {removeHotplugBtnText}
156	          </DropdownItem>
157	        )}
158	      </DropdownList>
159	    </Dropdown>
160	  );
161	};
162	
163	export default DiskRowActions;

